import React, { useEffect, useState } from "react";
import API from "../../api/api";

const CATS = [
  { value: "", label: "All" },
  { value: "web-development", label: "Web Dev" },
  { value: "mobile-development", label: "Mobile" },
  { value: "ui-ux-design", label: "UI/UX" },
  { value: "graphic-design", label: "Graphic" },
  { value: "backend-development", label: "Backend" },
  { value: "data-science", label: "Data Science" },
  { value: "devops-cloud", label: "DevOps" },
  { value: "content-writing", label: "Content" },
  { value: "digital-marketing", label: "Marketing" },
  { value: "other", label: "Other" },
];

const fmt = (d) => d ? new Date(d).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" }) : "";

export default function FindProjects() {
  const [projects, setProjects] = useState([]);
  const [search, setSearch] = useState("");
  const [cat, setCat] = useState("");
  const [appliedIds, setAppliedIds] = useState([]);
  const [modal, setModal] = useState(null);
  const [form, setForm] = useState({ bid: "", message: "" });
  const [submitting, setSubmitting] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([API.get("/projects"), API.get("/proposals/my")]).then(([pr, myPr]) => {
      setProjects(pr.data || []);
      setAppliedIds((myPr.data || []).map(p => p.project_id));
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const filtered = projects.filter(p => {
    const q = search.toLowerCase();
    return (!q || p.title?.toLowerCase().includes(q) || p.description?.toLowerCase().includes(q))
      && (!cat || p.category === cat);
  });

  const submit = async () => {
    if (!form.bid || !form.message) return alert("Fill all fields");
    setSubmitting(true);
    try {
      await API.post("/proposals", { project_id: modal.id, bid: form.bid, message: form.message });
      setAppliedIds(prev => [...prev, modal.id]);
      setModal(null); setForm({ bid: "", message: "" });
    } catch (e) { alert(e.response?.data?.message || "Error"); }
    setSubmitting(false);
  };

  const S = {
    page: { background: "#0f172a", minHeight: "100vh", padding: "32px", fontFamily: "'Segoe UI', sans-serif" },
    title: { fontSize: "24px", fontWeight: "700", color: "#f1f5f9", marginBottom: "4px" },
    sub: { fontSize: "13px", color: "#64748b", marginBottom: "24px" },
    searchBox: { background: "#1e293b", border: "1px solid #334155", borderRadius: "10px", padding: "10px 16px", color: "#f1f5f9", fontSize: "14px", width: "100%", outline: "none", marginBottom: "16px", boxSizing: "border-box" },
    catRow: { display: "flex", gap: "8px", flexWrap: "wrap", marginBottom: "24px" },
    catBtn: (active) => ({ padding: "6px 14px", borderRadius: "20px", fontSize: "12px", fontWeight: "600", cursor: "pointer", border: "none", background: active ? "#2dd4bf" : "#1e293b", color: active ? "#0f172a" : "#94a3b8", transition: "all 0.2s" }),
    grid: { display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(340px, 1fr))", gap: "16px" },
    card: { background: "#1e293b", border: "1px solid #334155", borderRadius: "14px", padding: "20px", transition: "border-color 0.2s" },
    cardTitle: { fontSize: "16px", fontWeight: "700", color: "#f1f5f9", marginBottom: "6px" },
    cardDesc: { fontSize: "13px", color: "#94a3b8", marginBottom: "14px", lineHeight: 1.5 },
    tags: { display: "flex", gap: "6px", flexWrap: "wrap", marginBottom: "14px" },
    tag: { background: "rgba(45,212,191,0.08)", color: "#2dd4bf", border: "1px solid rgba(45,212,191,0.2)", borderRadius: "6px", padding: "3px 10px", fontSize: "11px", fontWeight: "600" },
    meta: { display: "flex", gap: "16px", fontSize: "12px", color: "#64748b", marginBottom: "16px" },
    budget: { fontSize: "18px", fontWeight: "800", color: "#4ade80" },
    applyBtn: { width: "100%", padding: "10px", borderRadius: "9px", border: "none", fontSize: "13px", fontWeight: "700", cursor: "pointer", background: "linear-gradient(135deg, #0d9488, #0891b2)", color: "white", letterSpacing: "0.3px" },
    appliedBtn: { width: "100%", padding: "10px", borderRadius: "9px", border: "1px solid #334155", fontSize: "13px", fontWeight: "700", background: "transparent", color: "#4ade80", cursor: "default" },
    overlay: { position: "fixed", inset: 0, background: "rgba(0,0,0,0.7)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 50, padding: "20px" },
    modal: { background: "#1e293b", border: "1px solid #334155", borderRadius: "16px", padding: "28px", width: "100%", maxWidth: "440px" },
    mTitle: { fontSize: "17px", fontWeight: "700", color: "#f1f5f9", marginBottom: "4px" },
    mSub: { fontSize: "12px", color: "#64748b", marginBottom: "20px" },
    mLabel: { fontSize: "11px", fontWeight: "600", color: "#94a3b8", display: "block", marginBottom: "4px", textTransform: "uppercase", letterSpacing: "0.8px" },
    mInput: { width: "100%", padding: "10px 12px", background: "#0f172a", border: "1px solid #334155", borderRadius: "8px", color: "#f1f5f9", fontSize: "13px", outline: "none", boxSizing: "border-box", marginBottom: "14px" },
    mBtns: { display: "flex", gap: "10px", marginTop: "4px" },
    mSubmit: { flex: 1, padding: "10px", borderRadius: "8px", border: "none", background: "linear-gradient(135deg, #0d9488, #0891b2)", color: "white", fontWeight: "700", cursor: "pointer" },
    mCancel: { padding: "10px 18px", borderRadius: "8px", border: "1px solid #334155", background: "transparent", color: "#94a3b8", cursor: "pointer" },
  };

  if (loading) return <div style={{ ...S.page, display:"flex", alignItems:"center", justifyContent:"center" }}><span style={{ color:"#2dd4bf" }}>Loading...</span></div>;

  return (
    <div style={S.page}>
      <h1 style={S.title}>Find Projects</h1>
      <p style={S.sub}>Browse available projects and submit your proposals</p>

      <input style={S.searchBox} placeholder="Search by title or description..." value={search} onChange={e => setSearch(e.target.value)} />

      <div style={S.catRow}>
        {CATS.map(c => (
          <button key={c.value} style={S.catBtn(cat === c.value)} onClick={() => setCat(c.value)}>{c.label}</button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <div style={{ textAlign:"center", color:"#475569", padding:"60px" }}><div style={{ fontSize:"40px", marginBottom:"12px" }}>📭</div><p>No projects found</p></div>
      ) : (
        <div style={S.grid}>
          {filtered.map(p => {
            const applied = appliedIds.includes(p.id);
            return (
              <div key={p.id} style={S.card}>
                <h3 style={S.cardTitle}>{p.title}</h3>
                <p style={S.cardDesc}>{p.description?.slice(0, 100)}...</p>
                {p.skills && (
                  <div style={S.tags}>
                    {p.skills.split(",").slice(0,4).map((s,i) => <span key={i} style={S.tag}>{s.trim()}</span>)}
                  </div>
                )}
                <div style={S.meta}>
                  {p.deadline && <span>📅 {fmt(p.deadline)}</span>}
                  {p.proposals_count !== undefined && <span>📄 {p.proposals_count} proposals</span>}
                  {p.category && <span style={{ color:"#2dd4bf" }}>{p.category.replace(/-/g," ")}</span>}
                </div>
                <p style={S.budget}>₹{p.budget}</p>
                <div style={{ height:"12px" }} />
                {applied
                  ? <button style={S.appliedBtn}>✓ Applied</button>
                  : <button style={S.applyBtn} onClick={() => { setModal(p); setForm({ bid:"", message:"" }); }}>Apply Now</button>
                }
              </div>
            );
          })}
        </div>
      )}

      {modal && (
        <div style={S.overlay} onClick={e => e.target === e.currentTarget && setModal(null)}>
          <div style={S.modal}>
            <h2 style={S.mTitle}>Submit Proposal</h2>
            <p style={S.mSub}>{modal.title} · Budget: ₹{modal.budget}</p>
            <label style={S.mLabel}>Your Bid (₹)</label>
            <input style={S.mInput} type="number" placeholder="Enter your bid amount" value={form.bid} onChange={e => setForm({...form, bid: e.target.value})} />
            <label style={S.mLabel}>Cover Letter</label>
            <textarea style={{ ...S.mInput, height:"90px", resize:"none" }} placeholder="Why are you the best fit?" value={form.message} onChange={e => setForm({...form, message: e.target.value})} />
            <div style={S.mBtns}>
              <button style={S.mSubmit} onClick={submit} disabled={submitting}>{submitting ? "Submitting..." : "Submit Proposal"}</button>
              <button style={S.mCancel} onClick={() => setModal(null)}>Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
